// src/pages/HomeScreen.js
import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// ✅ taxi.png already includes: faint arch + big green pin + taxi
const taxiImg = require("../../assets/taxi.png");

// ✅ urban.png already includes: crest + “Communauté Urbaine de Yaoundé”
const cityLogo = require("../../assets/urban.png");

const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const plateNumber = "CE696KO";

  const goToOfficialControl = () => {
    // Home is the only screen for now
    // navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        style={styles.scroll}                        // ✅ important for web
        contentContainerStyle={styles.scrollContent} // ✅ padding so bottom never cuts
        showsVerticalScrollIndicator={false}
      >
        <View style={styles.screen}>
          {/* ===== HERO (NO extra circle, because it’s inside taxi.png) ===== */}
          <View style={styles.heroWrap}>
            <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
          </View>

          {/* ===== Vérifié ===== */}
          <View style={styles.statusRow}>
            <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
            <Text style={styles.statusText}>Vérifié</Text>
          </View>

          {/* ===== Plate ===== */}
          <View style={styles.plateWrap}>
            <Text style={styles.plateText}>{plateNumber}</Text>
          </View>

          {/* ===== Button (shield on the LEFT, correct size/position) ===== */}
          <TouchableOpacity
            activeOpacity={0.92}
            style={styles.officialBtn}
            onPress={goToOfficialControl}
          >
            <View style={styles.btnIconWrap}>
              <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
            </View>

            <Text style={styles.btnText}>Contrôle officiel</Text>
          </TouchableOpacity>

          {/* ===== Bottom logo (never cut) ===== */}
          <View style={styles.logoWrap}>
            <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#EEF3F7" },

  // ✅ makes ScrollView behave correctly on web
  scroll: { flex: 1 },

  // ✅ ensures content can scroll + bottom never cuts
  scrollContent: {
    paddingBottom: 90,
  },

  screen: {
    paddingTop: 18,
    paddingHorizontal: 18,
    alignItems: "center",
  },

  /* ===== HERO ===== */
  heroWrap: {
    width: "100%",
    alignItems: "center",
    justifyContent: "center",
    marginTop: 6,
  },

  // taxi “floats” directly (no extra background)
  taxi: {
    width: "100%",
    height: 320, // tuned to match mockup proportions
  },

  /* ===== STATUS ===== */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 8,
    gap: 12,
  },
  smallTick: { width: 40, height: 40 },

  statusText: {
    fontSize: 40, // closer to mockup
    fontWeight: "900",
    color: GREEN,
    letterSpacing: 0.2,
  },

  /* ===== PLATE ===== */
  plateWrap: {
    marginTop: 12,
    paddingHorizontal: 26,
    paddingVertical: 10,
    borderRadius: 12,
    borderWidth: 3,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
  },
  plateText: {
    fontSize: 44,
    fontWeight: "900",
    letterSpacing: 1,
    color: "#111827",
  },

  /* ===== BUTTON ===== */
  officialBtn: {
    marginTop: 16,
    width: "78%",     // like mockup (not full width)
    height: 62,
    backgroundColor: DARK_GREEN,
    borderRadius: 14,

    justifyContent: "center",
    alignItems: "center",

    shadowColor: "#000",
    shadowOpacity: 0.22,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 14 },
    elevation: 8,

    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.18)",

    // ✅ padding so the left icon fits nicely
    paddingLeft: 18,
    paddingRight: 18,
  },

  // ✅ shield position + size (left inside the button)
  btnIconWrap: {
    position: "absolute",
    left: 16,
    width: 34,
    height: 34,
    borderRadius: 10,
    alignItems: "center",
    justifyContent: "center",
    backgroundColor: "rgba(255,255,255,0.08)",
    borderWidth: 1,
    borderColor: "rgba(255,255,255,0.14)",
  },
  btnIcon: {
    width: 18,
    height: 18,
    opacity: 0.95,
  },

  btnText: {
    color: "#FFFFFF",
    fontSize: 24,
    fontWeight: "900",
    letterSpacing: 0.2,
  },

  /* ===== LOGO ===== */
  logoWrap: {
    marginTop: 18,
    alignItems: "center",
    width: "100%",
  },
  logo: {
    width: 240,
    height: 240,
  },
});
